'use strict';

const fs = require('fs');
const https = require('https');
const jwt = require('jsonwebtoken');
const { Client: ProjectClient } = require('magicbell-js/project-client');

// --- Environment variables ---
const runId = process.env.ZEALT_RUN_ID;
const magicbellEmail = process.env.MAGICBELL_EMAIL;
const apiKey = process.env.MAGICBELL_API_KEY;
const secretKey = process.env.MAGICBELL_SECRET_KEY;

if (!runId || !magicbellEmail || !apiKey || !secretKey) {
  console.error('Missing required environment variables.');
  process.exit(1);
}

// --- Derive user fields ---
const [localPart, domain] = magicbellEmail.split('@');
const userEmail = `${localPart}+topic-sub-${runId}@${domain}`;
const externalId = `user-topic-sub-${runId}`;
const topicName = `updates-${runId}`;

const LOG_FILE = '/home/user/myproject/output.log';

function log(msg) {
  const line = `[${new Date().toISOString()}] ${msg}`;
  console.log(line);
  fs.appendFileSync(LOG_FILE, line + '\n');
}

// --- Generate a User JWT ---
function generateUserJwt() {
  const payload = { sub: externalId };
  // MagicBell user JWTs are signed with the secret key; exp is optional but good practice
  return jwt.sign(payload, secretKey, { expiresIn: '1h' });
}

// --- Simple HTTPS request helper ---
function httpsRequest(options, body) {
  return new Promise((resolve, reject) => {
    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', (chunk) => { data += chunk; });
      res.on('end', () => {
        resolve({ statusCode: res.statusCode, headers: res.headers, body: data });
      });
    });
    req.on('error', reject);
    if (body) req.write(body);
    req.end();
  });
}

async function main() {
  // Clear / create log file
  fs.writeFileSync(LOG_FILE, '');

  log(`Run ID      : ${runId}`);
  log(`External ID : ${externalId}`);
  log(`User email  : ${userEmail}`);
  log(`Topic       : ${topicName}`);

  // 1. Upsert the user via ProjectClient
  log('Step 1: Upserting user via ProjectClient...');
  const projectClient = new ProjectClient({
    apiKey,
    secretKey,
  });

  const savedUser = await projectClient.users.saveUser({
    externalId,
    email: userEmail,
  });
  log(`User upserted. Status: ${savedUser.status}`);

  // 2. Generate a User JWT for the subscription request
  log('Step 2: Generating User JWT...');
  const userToken = generateUserJwt();
  log('User JWT generated.');

  // 3. Subscribe the user to the topic via REST (UserClient has no subscription API)
  log(`Step 3: Subscribing user to topic "${topicName}"...`);
  const bodyPayload = JSON.stringify({
    topic: topicName,
  });

  const options = {
    hostname: 'api.magicbell.com',
    path: '/subscriptions',
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Content-Length': Buffer.byteLength(bodyPayload),
      'X-MAGICBELL-API-KEY': apiKey,
      'X-MAGICBELL-USER-EXTERNAL-ID': externalId,
      'Authorization': `Bearer ${userToken}`,
    },
  };

  const response = await httpsRequest(options, bodyPayload);
  log(`Subscription response status: ${response.statusCode}`);
  log(`Subscription response body  : ${response.body}`);

  if (response.statusCode >= 200 && response.statusCode < 300) {
    log('Subscription successful');
  } else {
    log(`ERROR: Subscription failed with status ${response.statusCode}`);
    process.exit(1);
  }
}

main().catch((err) => {
  const msg = `FATAL ERROR: ${err.message || err}`;
  console.error(msg);
  fs.appendFileSync(LOG_FILE, msg + '\n');
  process.exit(1);
});

